), ins as (insert into map_questions(subject,grade,standard_id,passage_id,rit_band,difficulty,stem,stem_image_svg,audio_supported,explanation,source_note,is_active,question_format) select 'math'::map_subject,seed.grade,s.id,null,seed.rit_band::map_rit_band,seed.difficulty::map_difficulty,seed.stem,seed.stem_image_svg,true,seed.explanation,seed.source_note,true,'mcq' from seed join map_standards s on s.grade=seed.grade and s.subject='math'::map_subject and s.teks_code=seed.teks_code where not exists (select 1 from map_questions q where q.grade=seed.grade and q.subject='math'::map_subject and q.source_note=seed.source_note and q.stem=seed.stem) returning id,stem,source_note,grade) insert into map_question_choices(question_id,label,body,body_image_svg,is_correct,misconception,misconception_tag,sort_order) select ins.id,c.label,c.body,null,c.is_correct,c.misconception,c.misconception_tag,c.sort_order from ins join seed on seed.stem=ins.stem and seed.source_note=ins.source_note and seed.grade=ins.grade cross join lateral jsonb_to_recordset(seed.choices) as c(label char(1),body text,is_correct boolean,misconception text,misconception_tag text,sort_order smallint);